/**
 * kdoc MCP Server — 7 tools over stdio transport.
 * Follows the codegraph MCP pattern (McpServer + StdioServerTransport + safeHandler).
 */

import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import { z } from 'zod';
import fs from 'node:fs';
import path from 'node:path';
import { checkCodegraph, degradedReconcile, degradedImpact } from './codegraph-client.js';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ToolResponse {
  [x: string]: unknown;
  content: Array<{ type: 'text'; text: string }>;
  structuredContent: Record<string, unknown>;
}

// ---------------------------------------------------------------------------
// Dynamic engine import
// ---------------------------------------------------------------------------

/**
 * Lazily import and cache the governance engine (ESM .mjs at package root).
 * The engine is outside the CLI build, so we use dynamic import.
 */
let _engineCache: Awaited<ReturnType<typeof loadEngine>> | null = null;

async function loadEngine() {
  const enginePath = path.resolve(
    path.dirname(new URL(import.meta.url).pathname),
    '..', '..', '..', 'core', 'governance-engine.mjs',
  );
  return await import(enginePath);
}

async function cachedEngine() {
  if (!_engineCache) {
    _engineCache = await loadEngine();
  }
  return _engineCache;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function textResponse(text: string, data?: Record<string, unknown>): ToolResponse {
  return {
    content: [{ type: 'text', text }],
    structuredContent: data ?? {},
  };
}

function safeHandler<T>(fn: (args: T) => Promise<ToolResponse>): (args: T) => Promise<ToolResponse> {
  return async (args: T) => {
    try {
      return await fn(args);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      return textResponse(`Error: ${msg}`, { error: msg });
    }
  };
}

// ---------------------------------------------------------------------------
// Version
// ---------------------------------------------------------------------------

function getPackageVersion(): string {
  try {
    const pkgPath = path.resolve(
      path.dirname(new URL(import.meta.url).pathname),
      '..', '..', 'package.json',
    );
    return JSON.parse(fs.readFileSync(pkgPath, 'utf-8')).version;
  } catch {
    return '0.0.0';
  }
}

// ---------------------------------------------------------------------------
// Tool handlers
// ---------------------------------------------------------------------------

async function handleHealth(args: { repoPath: string }): Promise<ToolResponse> {
  const engine = await cachedEngine();
  const report = engine.runGovernance(args.repoPath);
  // Emit governance check event after successful health check
  engine.emitDaemonEvent('kdoc.governance_check', {
    healthScore: report.healthScore,
    violationCount: report.violations.length,
    suggestionCount: report.suggestions.length,
    repoPath: args.repoPath,
  });
  const summary = `Health: ${report.healthScore}/100 | ${report.violations.length} violation(s) | ${report.suggestions.length} suggestion(s)`;
  return textResponse(summary, report);
}

async function handleValidate(args: { filePath: string }): Promise<ToolResponse> {
  const engine = await cachedEngine();
  const result = engine.validateFile(args.filePath);
  const status = result.valid ? 'Valid' : `Invalid: ${result.errors.map((e: { message: string }) => e.message).join('; ')}`;
  return textResponse(status, result);
}

async function handleCoverage(args: { repoPath: string; paths?: string[] }): Promise<ToolResponse> {
  const engine = await cachedEngine();
  const coverage = engine.getCoverage(args.repoPath, args.paths);
  const areas = Object.entries(coverage.byArea)
    .map(([name, data]: [string, any]) => `${name}: ${data.fileCount} files, ${data.complete ? 'complete' : 'incomplete'}`)
    .join('\n');
  return textResponse(areas || 'No coverage data', coverage);
}

async function handleSuggest(args: { repoPath: string; changedFiles?: string[] }): Promise<ToolResponse> {
  const engine = await cachedEngine();
  const report = engine.runGovernance(args.repoPath);

  // Emit doc_drift event for suggestions
  engine.emitDaemonEvent('kdoc.doc_drift', {
    changedFiles: args.changedFiles ?? [],
    suggestionCount: report.suggestions.length,
  });

  const text = report.suggestions.length > 0
    ? report.suggestions.map((s: any) => `[${s.priority}] ${s.type}: ${s.reason}`).join('\n')
    : 'No suggestions — documentation looks complete.';
  return textResponse(text, { suggestions: report.suggestions });
}

async function handleSchema(args: { kind?: string }): Promise<ToolResponse> {
  const engine = await cachedEngine();
  const schemas = engine.loadSchemas();

  if (args.kind) {
    const typeDef = schemas.frontmatter.types[args.kind];
    if (!typeDef) {
      return textResponse(`Unknown document kind: ${args.kind}`, { error: `Unknown kind: ${args.kind}` });
    }
    return textResponse(JSON.stringify(typeDef, null, 2), { kind: args.kind, schema: typeDef });
  }

  return textResponse(
    `Structure: ${Object.keys(schemas.structure.areas).length} areas\nTypes: ${Object.keys(schemas.frontmatter.types).join(', ')}`,
    schemas,
  );
}

async function handleReconcile(args: { repoPath: string; path: string }): Promise<ToolResponse> {
  const engine = await cachedEngine();
  const cg = checkCodegraph(args.repoPath);

  // Run reconciliation — degraded with grep heuristics when CodeGraph unavailable
  const result = degradedReconcile(args.repoPath, args.path);
  const driftCount = result.driftItems.filter(d => d.severity !== 'info').length;

  // Emit doc_drift event when drift detected
  if (driftCount > 0) {
    engine.emitDaemonEvent('kdoc.doc_drift', {
      degraded: !cg.available,
      path: args.path,
      driftCount,
      confidence: result.confidence,
    });
  }

  const text = result.driftItems.length > 0
    ? result.driftItems.map(d => `[${d.severity}] ${d.finding}`).join('\n')
    : 'No drift detected.';

  return textResponse(
    `Reconcile (${result.confidence} confidence, ${cg.available ? 'codegraph' : 'heuristic'}):\n${text}`,
    { ...result, codegraphAvailable: cg.available },
  );
}

async function handleImpact(args: { repoPath: string; changedFiles: string[] }): Promise<ToolResponse> {
  if (args.changedFiles.length === 0) {
    return textResponse('No changed files provided', { affectedDocs: [] });
  }

  const cg = checkCodegraph(args.repoPath);

  // Run impact analysis — degraded with path heuristics when CodeGraph unavailable
  const result = degradedImpact(args.repoPath, args.changedFiles);

  const text = result.affectedDocs.length > 0
    ? result.affectedDocs.map(d => `[${d.confidence}] ${d.doc}: ${d.reason}`).join('\n')
    : 'No affected Knowledge documents found.';

  return textResponse(
    `Impact (${cg.available ? 'codegraph' : 'heuristic'}):\n${text}`,
    { ...result, codegraphAvailable: cg.available },
  );
}

// ---------------------------------------------------------------------------
// Server startup
// ---------------------------------------------------------------------------

export async function startServer(projectDir: string): Promise<void> {
  const server = new McpServer({
    name: 'kdoc',
    version: getPackageVersion(),
  });

  // --- kdoc_health ---
  server.registerTool(
    'kdoc_health',
    {
      description: 'Run a full Knowledge governance health check — returns health score, violations, coverage, and suggestions',
      inputSchema: {
        repoPath: z.string().describe('Absolute path to the project root'),
      },
    },
    safeHandler(async (args) => handleHealth(args as { repoPath: string })),
  );

  // --- kdoc_validate ---
  server.registerTool(
    'kdoc_validate',
    {
      description: 'Validate frontmatter of a specific Knowledge document against schema',
      inputSchema: {
        filePath: z.string().describe('Absolute path to the file to validate'),
      },
    },
    safeHandler(async (args) => handleValidate(args as { filePath: string })),
  );

  // --- kdoc_coverage ---
  server.registerTool(
    'kdoc_coverage',
    {
      description: 'Get documentation coverage metrics by Knowledge area',
      inputSchema: {
        repoPath: z.string().describe('Absolute path to the project root'),
        paths: z.array(z.string()).optional().describe('Limit to specific paths'),
      },
    },
    safeHandler(async (args) => handleCoverage(args as { repoPath: string; paths?: string[] })),
  );

  // --- kdoc_suggest ---
  server.registerTool(
    'kdoc_suggest',
    {
      description: 'Suggest missing documentation based on project structure and changed files',
      inputSchema: {
        repoPath: z.string().describe('Absolute path to the project root'),
        changedFiles: z.array(z.string()).optional().describe('Recently changed files to focus suggestions on'),
      },
    },
    safeHandler(async (args) => handleSuggest(args as { repoPath: string; changedFiles?: string[] })),
  );

  // --- kdoc_schema ---
  server.registerTool(
    'kdoc_schema',
    {
      description: 'Return the current Knowledge schema definitions (frontmatter fields, status values, area structure)',
      inputSchema: {
        kind: z.string().optional().describe('Document kind to return schema for (e.g., "adr", "feature"). Omit for full schema.'),
      },
    },
    safeHandler(async (args) => handleSchema(args as { kind?: string })),
  );

  // --- kdoc_reconcile ---
  server.registerTool(
    'kdoc_reconcile',
    {
      description: 'Compare documentation against code reality (requires CodeGraph for full analysis, degrades gracefully without)',
      inputSchema: {
        repoPath: z.string().describe('Absolute path to the project root'),
        path: z.string().describe('Specific path to reconcile within the project'),
      },
    },
    safeHandler(async (args) => handleReconcile(args as { repoPath: string; path: string })),
  );

  // --- kdoc_impact ---
  server.registerTool(
    'kdoc_impact',
    {
      description: 'Determine which Knowledge documents are affected by code changes (requires CodeGraph, degrades gracefully)',
      inputSchema: {
        repoPath: z.string().describe('Absolute path to the project root'),
        changedFiles: z.array(z.string()).describe('List of changed file paths'),
      },
    },
    safeHandler(async (args) => handleImpact(args as { repoPath: string; changedFiles: string[] })),
  );

  const transport = new StdioServerTransport();
  await server.connect(transport);
}

// ---------------------------------------------------------------------------
// CLI entry point
// ---------------------------------------------------------------------------

export function parseProjectDir(argv: string[], fallback: string): string {
  const idx = argv.indexOf('--project');
  if (idx !== -1 && argv[idx + 1] && argv[idx + 1].trim() !== '') {
    return path.resolve(argv[idx + 1]);
  }
  return fallback;
}
